codeExample1.code:
/* file: math_utils.h */
#ifndef MATH_UTILS_H
#define MATH_UTILS_H

/* Define mathematical constants */
#define PI 3.14159265358979323846

/* Function-like macro: Safely compute the square of an expression */
#define SAFE_SQUARE(x) ((x) * (x))

/* Function-like macro: Get maximum value safely */
#define MAX_VAL(a, b) (((a) > (b)) ? (a) : (b))

#endif /* MATH_UTILS_H */

/* file: main.c */
#include <stdio.h>
#include "math_utils.h"
#include "math_utils.h" /* Re-include to prove the Header Guard works */

int main(void) {
    int num = 5;
    /* Test basic macro expansion */
    printf("Square of %d is: %d\n", num, SAFE_SQUARE(num));

    /* Illustrate correct operator precedence preservation */
    /* Expands to: ((num + 1) * (num + 1)) -> (6 * 6) = 36 */
    printf("Square of (%d + 1) is: %d\n", num, SAFE_SQUARE(num + 1));

    /* Get maximum of two numbers */
    printf("Max of 10 and 20 is: %d\n", MAX_VAL(10, 20));
    return 0;
}

codeExample2.code:
#include <stdio.h>

/* Define configuration level */
#define DEBUG_LEVEL 2

/* Platform check */
#if defined(_WIN32)
    #define PLATFORM_NAME "Windows OS"
#elif defined(__linux__)
    #define PLATFORM_NAME "Linux OS"
#else
    #define PLATFORM_NAME "Unknown OS"
#endif

/* Struct alignment using Pragma Pack */
#pragma pack(push, 1) /* Force structural alignment of 1 byte (remove padding) */
typedef struct {
    char identifier;
    int network_address;
} PackedPacket;
#pragma pack(pop) /* Restore default alignment settings */

typedef struct {
    char identifier;
    int network_address;
} StandardPacket;

int main(void) {
    /* 1. Print conditional compilation output */
    printf("Platform identified: %s\n", PLATFORM_NAME);

    /* Conditional execution block */
    #if (DEBUG_LEVEL >= 2)
        printf("[VERBOSE DEBUG] Verbose compilation mode is enabled.\n");
    #elif (DEBUG_LEVEL == 1)
        printf("[INFO DEBUG] Basic debugging active.\n");
    #else
        printf("[PRODUCTION] No debug assertions active.\n");
    #endif

    /* 2. Compare Packed vs Standard Struct alignment sizes */
    printf("Size of PackedPacket: %zu bytes\n", sizeof(PackedPacket));
    printf("Size of StandardPacket: %zu bytes\n", sizeof(StandardPacket));

    return 0;
}

