#include <stdio.h>

#pragma pack(push, 1)
typedef struct {
    char category;
    short level;
    char version;
    short checksum;
} TelemetryFrame; 
#pragma pack(pop)

int main(void) {
    printf("Size of TelemetryFrame: %zu\n", sizeof(TelemetryFrame));
    return 0;
}

/* Output is exactly 6 bytes. Under natural 32-bit alignment: 
   char (1) + padding (1) + short (2) + char (1) + padding (1) + short (2) = 8 bytes. */

