What will be the exact console output of the following preprocessor-driven program?

#define VAL 5 + 5
int main() {
    int ans = VAL * VAL;
    printf("%d", ans);
    return 0;
}

What does the following preprocessor construct output?

#define STR(x) #x
#define CONCAT(a, b) a##b
int main() {
    printf("%s", STR(CONCAT(1, 2)));
    return 0;
}

Analyze the output of the following code:

#define OPTION 1
int main() {
    int state = 0;
    #if OPTION == 0
        state = 100;
    #elif OPTION == 1
        state = 200;
    #else
        state = 300;
    #endif
    printf("%d", state);
    return 0;
}

